import React, { useState, useRef, useEffect } from 'react';
import { MoreVertical, Bookmark, Eye, CheckCircle2 } from 'lucide-react';

const NudgeCard = ({ nudge, isSelected, onClick, onCreateTodo, onMarkComplete, onReply, onSnooze, onArchive, onMarkUnread, onPinNudge, onMarkResolved }) => {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Fechar dropdown ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsDropdownOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const getStatusDotColor = (status) => {
    switch (status) {
      case 'online': return 'bg-green-500';
      case 'away': return 'bg-orange-500';
      case 'offline': return 'bg-gray-500';
      default: return 'bg-green-500';
    }
  };



  // Truncar mensagem para 2 linhas
  const truncateMessage = (text, maxLines = 2) => {
    const words = text.split(' ');
    const wordsPerLine = 8; // Aproximadamente 8 palavras por linha
    const maxWords = maxLines * wordsPerLine;

    if (words.length <= maxWords) {
      return text;
    }

    return words.slice(0, maxWords).join(' ') + '...';
  };

  return (
    <div 
      className={`cursor-pointer transition-all duration-200 rounded-lg p-4 group ${
        isSelected 
          ? 'border border-white' 
          : nudge.isRead 
            ? 'bg-transparent border border-neutral-800 hover:bg-neutral-800/50 hover:border-neutral-700'
            : 'bg-neutral-800 border border-neutral-600 hover:bg-neutral-600 hover:border-neutral-500'
      }`}
      onClick={onClick}
    >
      {/* Header com avatar, nome, cargo e menu */}
      <div className="flex items-start gap-3 mb-3">
        <div className="relative">
          <img 
            src={nudge.senderAvatar} 
            alt={`${nudge.senderName} Profile`} 
            className="w-9 h-9 rounded-full object-cover"
          />
          <div className={`absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 ${getStatusDotColor('online')} rounded-full border-2 border-gray-900`}></div>
        </div>
        <div className="flex-1 min-w-0">
          <h3 className="text-white font-medium text-base">{nudge.senderName}</h3>
          <div className="flex items-center gap-2">
            <p className="text-neutral-400 text-sm truncate">{nudge.senderTitle}</p>
            <span className="text-neutral-400 text-sm whitespace-nowrap">• {nudge.timestamp}</span>
          </div>
        </div>
        <div className="relative flex items-center gap-2" ref={dropdownRef}>
          {/* Bookmark icon when pinned */}
          {nudge.isPinned && (
            <Bookmark className="w-4 h-4 text-white fill-white" />
          )}
          <button
            className="p-1 hover:bg-neutral-800 rounded transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              setIsDropdownOpen(!isDropdownOpen);
            }}
          >
            <MoreVertical className="w-5 h-5 text-neutral-400" />
          </button>

          {/* Dropdown Menu */}
          {isDropdownOpen && (
            <div className="absolute right-0 top-8 w-48 bg-neutral-800 border border-neutral-700 rounded-lg shadow-lg z-10">
              <div className="py-1">
                <button
                  className="w-full px-3 py-2 text-left text-sm text-white hover:bg-neutral-700 flex items-center gap-2"
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsDropdownOpen(false);
                    if (onMarkUnread) {
                      onMarkUnread(nudge.id);
                    }
                  }}
                >
                  <Eye className="w-4 h-4" />
                  Mark as unread
                </button>
                <button
                  className="w-full px-3 py-2 text-left text-sm text-white hover:bg-neutral-700 flex items-center gap-2"
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsDropdownOpen(false);
                    if (onPinNudge) {
                      onPinNudge(nudge.id);
                    }
                  }}
                >
                  <Star className="w-4 h-4" />
                  Pin nudge
                </button>
                {!nudge.isRead && (
                  <button
                    className="w-full px-3 py-2 text-left text-sm text-white hover:bg-neutral-700 flex items-center gap-2"
                    onClick={(e) => {
                      e.stopPropagation();
                      setIsDropdownOpen(false);
                      if (onMarkResolved) {
                        onMarkResolved(nudge.id);
                      }
                    }}
                  >
                    <CheckCircle2 className="w-4 h-4" />
                    Mark as resolved
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Mensagem com notificação - truncada em 2 linhas */}
      <div className="mb-3 flex items-start gap-3">
        <p className="text-white text-sm leading-relaxed flex-1">
          {truncateMessage(nudge.message, 2)}
        </p>
        {!nudge.isRead && (
          <div className="w-4 h-4 bg-red-500 rounded flex items-center justify-center flex-shrink-0 mt-0.5">
            <span className="text-white text-xs font-bold leading-none">1</span>
          </div>
        )}
      </div>


    </div>
  );
};

export default NudgeCard;
